import { Link, useNavigate } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";

function Sidebar({ role }) {

  const navigate = useNavigate();

  const { logout } = useAuth();

  const handleLogout = () => {

    logout();

    navigate("/login");
  };

  const menuItems = {

    faculty: [
      {
        name: "Dashboard",
        path: "/faculty/dashboard"
      },
      {
        name: "Questionnaire",
        path: "/faculty/questionnaire"
      },
      {
        name: "My Submissions",
        path: "/faculty/submissions"
      },
      {
        name: "Profile",
        path: "/profile"
      }
    ],

    hod: [
      {
        name: "Dashboard",
        path: "/hod/dashboard"
      },
      {
        name: "Faculty Review",
        path: "/hod/faculty-review"
      },
      {
        name: "HOD Questionnaire",
        path: "/hod/questionnaire"
      },
      {
        name: "Profile",
        path: "/profile"
      }
    ],

    dean: [
      {
        name: "Dashboard",
        path: "/dean/dashboard"
      },
      {
        name: "Faculty Review",
        path: "/dean/faculty-review"
      },
      {
        name: "HOD Review",
        path: "/dean/hod-review"
      },
      {
        name: "Dean Questionnaire",
        path: "/dean/questionnaire"
      },
      {
        name: "Analytics",
        path: "/dean/analytics"
      }
    ],

    admin: [
      {
        name: "Dashboard",
        path: "/admin/dashboard"
      },
      {
        name: "Users",
        path: "/admin/users"
      },
      {
        name: "Submissions",
        path: "/admin/submissions"
      },
      {
        name: "Analytics",
        path: "/admin/analytics"
      },
      {
        name: "Reports",
        path: "/admin/reports"
      }
    ]
  };

  return (
    <div
      style={{
        width: "250px",
        minHeight: "100vh",
        background: "#1f2937",
        color: "white",
        padding: "20px"
      }}
    >
      <h2>
        IQAC Portal
      </h2>

      <hr />

      {
        menuItems[role]?.map(
          (item) => (
            <div
              key={item.path}
              style={{
                margin:
                  "15px 0"
              }}
            >
              <Link
                to={item.path}
                style={{
                  color: "white",
                  textDecoration:
                    "none"
                }}
              >
                {item.name}
              </Link>
            </div>
          )
        )
      }

      <hr />

      <button
        onClick={
          handleLogout
        }
        style={{
          padding: "10px",
          width: "100%"
        }}
      >
        Logout
      </button>

    </div>
  );
}

export default Sidebar;
